package com.weekly.analytics.dto;

/**
 * A single rule-based prediction produced by the {@code PredictionService}.
 *
 * <p>Predictions are generated by evaluating historical patterns from the
 * analytics materialized views ({@code mv_user_weekly_summary},
 * {@code mv_outcome_coverage_weekly}) and the current plan state.
 *
 * @param type       the prediction type identifier (e.g. {@code "CARRY_FORWARD"},
 *                   {@code "LATE_LOCK"}, {@code "COVERAGE_DECLINE"})
 * @param likely     {@code true} when the rule conditions are met
 * @param confidence confidence level: {@code HIGH}, {@code MEDIUM}, or {@code LOW}
 * @param reason     human-readable explanation of why the prediction was made
 */
public record Prediction(
        String type,
        boolean likely,
        String confidence,
        String reason
) {}
